const crypto = require('crypto');

const flowConfig = $('Flow Config').first().json;
const body = $('Flow Endpoint').first().json.body;

// --- Private Key ---
let rawKey = flowConfig.flow_private_key;
rawKey = rawKey.replace(/^["']|["']$/g, '');
rawKey = rawKey.replace(/\\n/g, '\n');
rawKey = rawKey.replace(/\\r/g, '');

let keyType = 'PRIVATE KEY';
if (rawKey.includes('RSA PRIVATE KEY')) {
  keyType = 'RSA PRIVATE KEY';
}

const base64Body = rawKey
  .replace(/-----[A-Z ]+-----/g, '')
  .replace(/\s/g, '');

const cleanPem = [
  '-----BEGIN ' + keyType + '-----',
  ...base64Body.match(/.{1,64}/g),
  '-----END ' + keyType + '-----',
  ''
].join('\n');

const keyObj = crypto.createPrivateKey(cleanPem);
const privateKeyPem = keyObj.export({ type: 'pkcs1', format: 'pem' });

// --- Decrypt ---
const encryptedAesKey = Buffer.from(body.encrypted_aes_key, 'base64');
const encryptedFlowData = Buffer.from(body.encrypted_flow_data, 'base64');
const initialVectorBuffer = Buffer.from(body.initial_vector, 'base64');

const aesKey = crypto.privateDecrypt(
  { key: privateKeyPem, padding: crypto.constants.RSA_PKCS1_OAEP_PADDING, oaepHash: 'sha256' },
  encryptedAesKey
);

const TAG_LENGTH = 16;
const decipher = crypto.createDecipheriv('aes-128-gcm', aesKey, initialVectorBuffer);
decipher.setAuthTag(encryptedFlowData.subarray(-TAG_LENGTH));
const decrypted = Buffer.concat([
  decipher.update(encryptedFlowData.subarray(0, -TAG_LENGTH)),
  decipher.final()
]).toString('utf-8');
const request = JSON.parse(decrypted);

return [{
  json: {
    action: request.action,
    version: request.version || '3.0',
    data: request.data || {},
    flow_token: request.data?.flow_token || '',
    screen: request.screen || '',
    aesKeyBuffer: { data: Array.from(aesKey) },
    ivBuffer: { data: Array.from(initialVectorBuffer) }
  }
}];

const decrypted = $('Decryption').first().json;
const formData = decrypted.data || {};
const screen = decrypted.screen || '';

// TODO: Conectar com Odoo para buscar dados dinamicos
// Por enquanto, retorna resposta basica para qualquer data_exchange

const responseData = {
  version: '3.0',
  data: {
    status: 'active'
  }
};

return [{
  json: {
    response_to_send: responseData
  }
}];

const crypto = require("crypto");

const responsePayload = $input.first().json.response_to_send;

const aesKeyBuffer = Buffer.from($('Decryption').first().json.aesKeyBuffer.data);
const ivBuffer = Buffer.from($('Decryption').first().json.ivBuffer.data);

const flippedIV = Buffer.from(ivBuffer.map(b => ~b));

const cipher = crypto.createCipheriv("aes-128-gcm", aesKeyBuffer, flippedIV);

const encryptedResponse = Buffer.concat([
  cipher.update(JSON.stringify(responsePayload), "utf-8"),
  cipher.final(),
  cipher.getAuthTag(),
]);

return [{
  json: {
    response: encryptedResponse.toString("base64"),
  },
}];
